/*! Minimal Fuse.js-compatible local search helper */
(function (global) {
  function normalize(v) {
    return String(v || '').toLowerCase();
  }

  function flatten(item, keys) {
    return keys
      .map(function (key) {
        var value = item[key];
        if (Array.isArray(value)) {
          return value.join(' ');
        }
        return value == null ? '' : String(value);
      })
      .join(' ')
      .toLowerCase();
  }

  function scoreIndex(text, query) {
    var index = text.indexOf(query);
    if (index === -1) return null;
    return index / Math.max(text.length, 1);
  }

  function Fuse(list, options) {
    this.list = Array.isArray(list) ? list : [];
    this.options = options || {};
    this.keys = Array.isArray(this.options.keys) ? this.options.keys : [];
    this.includeScore = !!this.options.includeScore;
  }

  Fuse.prototype.search = function (query) {
    var q = normalize(query).trim();
    if (!q) {
      return this.list.map(function (item) {
        return { item: item, score: 0 };
      });
    }

    var keys = this.keys;
    var results = [];

    this.list.forEach(function (item) {
      var haystack = keys.length ? flatten(item, keys) : normalize(JSON.stringify(item));
      var score = scoreIndex(haystack, q);
      if (score !== null) {
        results.push({ item: item, score: score });
      }
    });

    results.sort(function (a, b) {
      return a.score - b.score;
    });

    return this.includeScore ? results : results.map(function (r) { return r.item; });
  };

  global.Fuse = Fuse;
})(window);
